3535	[IsIso plumbing from the unit square]
3536	  \label{lem:isiso_sheafifyeta_of_unitsquare}
3537	  \lean{AlgebraicGeometry.Scheme.Modules.isIso_sheafifyEta_of_unitSquare}
3538	  \uses{lem:pullback_unit_iso}
3539	  Suppose the \emph{unit square}
